// bulkSelectData is the Alpine component backing selection state. It is emitted
// once per list as an x-data initializer string so the table, bar, and modal
// share one reactive store. ids is unused server-side; selection is client-only.
func bulkSelectData(rowIDs []string) string {
	return fmt.Sprintf(`{
		selected: [],
		confirmAction: null,
		get allSelected() { return this.rowIds.length > 0 && this.selected.length === this.rowIds.length; },
		rowIds: %s,
		toggle(id, on) { if (on) { if (!this.selected.includes(id)) this.selected.push(id); } else { this.selected = this.selected.filter(x => x !== id); } },
		toggleAll(on) { this.selected = on ? [...this.rowIds] : []; },
		clear() { this.selected = []; this.confirmAction = null; },
		submitBulk(action) { this.$refs.bulkActionInput.value = action; this.$refs.bulkForm.submit(); }
	}`, jsStringArray(rowIDs))
}

